SELECT COUNT(*) AS session_count
FROM diagnostic_sessions
WHERE vehicle_id = 1;

SELECT MIN(reading_value) AS min_reading
FROM session_readings
WHERE item_id = (SELECT item_id FROM measurement_items WHERE item_name = 'Input Turbine Speed');

SELECT make, model 
FROM vehicles 
WHERE mileage > (SELECT AVG(mileage) FROM vehicles);

SELECT COUNT(vehicle_id)
FROM vehicles
WHERE owner_id = (SELECT owner_id FROM owners WHERE email = 'bob.smith@example.com');
